const output = $('Information Extractor1').first().json.output ?? {};
const base = { ...$json };

// ---------- Utils ----------
function normalizeKey(key) {
  return String(key)
    .trim()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
}

function normalizeValue(v) {
  if (v === null || v === undefined) return null;
  if (typeof v === 'string') {
    const t = v.trim();
    if (!t) return null;
    if (t.toLowerCase() === 'null') return null;
    return t;
  }
  return v;
}

function has(v) {
  if (v === null || v === undefined) return false;
  if (typeof v === 'string') return normalizeValue(v) !== null;
  if (Array.isArray(v)) return v.length > 0;
  if (typeof v === 'object') return Object.keys(v).length > 0;
  return true;
}

// ====== 1) estado do lead (base + output) ======
const state = {};

// 1.1) inclui base normalizado
for (const [k, v] of Object.entries(base)) {
  const nk = normalizeKey(k);
  const nv = normalizeValue(v);
  if (nv === null) continue;
  state[nk] = nv;
}

// 1.2) inclui output normalizado (sobrescreve base)
for (const [k, v] of Object.entries(output)) {
  const nk = normalizeKey(k);
  const nv = normalizeValue(v);
  if (nv === null) continue;
  state[nk] = nv;
}

// ====== 4) monta payload com TUDO que tem valor + id sempre ======
const payload = {};

// id sempre (mesmo se vazio)
payload.id = base.id ?? state.id ?? null;

// inclui todos os campos do state que têm valor
for (const [k, v] of Object.entries(state)) {
  if (k === 'id') continue; // já garantimos acima
  if (!has(v)) continue;
  payload[k] = v;
}

return [{ json: payload }];

