// Função para converter abreviações de unidades em texto por extenso
function normalizeUnits(text) {
  if (typeof text !== 'string') return text;

  // Números + unidade (15 mm, 2,5 mm, 3.2 mm, etc.)
  text = text.replace(/\b(\d+(?:[.,]\d+)?)\s*mm\b/gi, '$1 milímetros');
  text = text.replace(/\b(\d+(?:[.,]\d+)?)\s*cm\b/gi, '$1 centímetros');
  text = text.replace(/\b(\d+(?:[.,]\d+)?)\s*m\b(?![a-zA-Z0-9])/gi, '$1 metros'); // cuidado com 'm²'

  // Só a unidade sozinha (sem número antes)
  text = text.replace(/\bmm\b/gi, 'milímetros');
  text = text.replace(/\bcm\b/gi, 'centímetros');

  // Exemplos extra, se quiser:
  text = text.replace(/\bm²\b/gi, 'metros quadrados');
  text = text.replace(/\bm3\b/gi, 'metros cúbicos');
  text = text.replace(/\bm³\b/gi, 'metros cúbicos');
  text = text.replace(/\bkg\b/gi, 'quilos');

  return text;
}

return items.map(item => {
  const r = item.json.resposta; // o que você tinha antes

  let messagesArray;

  // Caso 1: resposta já é um objeto { messages: [...] }
  if (r && Array.isArray(r.messages)) {
    messagesArray = r.messages;
  }
  // Caso 2: resposta veio como string JSON
  else if (typeof r === 'string') {
    try {
      const parsed = JSON.parse(r);
      if (parsed && Array.isArray(parsed.messages)) {
        messagesArray = parsed.messages;
      } else if (Array.isArray(parsed)) {
        messagesArray = parsed;
      }
    } catch (e) {
      // não é JSON, deixa passar
    }
  }

  let textoFinal;

  // Se achamos um array de mensagens, junta tudo
  if (messagesArray) {
    // aqui você pode mudar o separador, se quiser quebra de linha coloca '\n\n'
    textoFinal = messagesArray.join(' ');
  } else {
    // fallback: manda como string mesmo
    textoFinal = String(r ?? '');
  }

  // Aqui entra a correção das unidades (mm -> milímetros, etc.)
  item.json.respostaTexto = normalizeUnits(textoFinal);

  return item;
});

