// Junta o histórico inteiro em uma única saída (texto) em ordem
// + repassa variáveis dos nós anteriores (Formatar Telefone / If / etc)

const items = $input.all();

// 1) Ordena pelo id (garante sequência correta)
items.sort((a, b) => (a.json?.id ?? 0) - (b.json?.id ?? 0));

// 2) Monta o texto do histórico
const history = items
  .map((it) => {
    const type = (it.json?.message?.type ?? 'unknown').toString().toUpperCase();
    const content = (it.json?.message?.content ?? '').toString().trim();
    if (!content) return null;

    const clean = content
      .replace(/\r/g, '')
      .replace(/[ \t]+\n/g, '\n')
      .replace(/\n{3,}/g, '\n\n')
      .trim();

    return `${type}: ${clean}`;
  })
  .filter(Boolean)
  .join('\n\n');

// 3) Puxa variáveis dos nós anteriores (ajuste os nomes se estiverem diferentes)
const phoneE164 = $('Formatar Telefone2').first()?.json?.phoneE164 ?? null;

// Se esse node realmente se chama "If" e é o que contém os campos do lead:
const lead = $('puxar contato1').first()?.json ?? {};
const detalhes = $('Dados2').first()?.json ?? {};

// (opcional) também dá pra puxar de outros nós, ex:
// const contato = $('puxar contato').first()?.json ?? {};

// 4) Retorna 1 item só, com histórico + variáveis repassadas
return [
  {
    json: {
      // histórico agregado
      history,

      // variáveis do "Formatar Telefone"
      phoneE164,

      // variáveis do node "If" (repasse direto)
      ...lead,detalhes,
    },
  },
];
